arguments.new_str:
using System.ComponentModel;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Initialize tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

var notebook = new ResearchNotebook();
var webSearch = new WebSearchTool(httpClient);

// --- Build AI client with automatic function invocation ---
using var agent = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation(configure: fi =>
    {
        fi.MaximumIterationsPerRequest = 15;
        fi.MaximumConsecutiveErrorsPerRequest = 3;
    })
    .Build(services: null!);

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchAsync),
        AIFunctionFactory.Create(webSearch.FetchPageAsync),
        AIFunctionFactory.Create(notebook.TakeNote),
        AIFunctionFactory.Create(notebook.GetAllNotes),
    ],
};

// --- System prompt ---
const string systemPrompt = """
    You are a research agent. Your goal is to thoroughly research a given topic using the available tools.

    Follow this process:
    1. Search the web with 2-3 varied queries to get broad coverage of the topic
    2. Fetch the most promising web pages for detailed information
    3. Take notes on each key finding (use TakeNote for every important fact or insight)
    4. After gathering enough information, review all notes with GetAllNotes
    5. Synthesize everything into a clear, well-organized summary with source citations

    Guidelines:
    - Take notes frequently so you don't lose information between steps
    - Use different search queries to cover multiple angles of the topic
    - When fetching pages, focus on authoritative and informative sources
    - Be factual and objective in your summary
    - Cite sources (URLs) when possible
    """;

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

try
{
    await foreach (var update in agent.GetStreamingResponseAsync(messages, chatOptions))
    {
        Console.Write(update.Text);
    }

    Console.WriteLine();

    var notes = notebook.GetAllNotes();
    if (notes.Count > 0)
    {
        Console.WriteLine($"\n{"",3}{"═══ Research Notes ═══",0}");
        for (var i = 0; i < notes.Count; i++)
        {
            Console.WriteLine($"\n  [{i + 1}] {notes[i].Title}");
            Console.WriteLine($"      {notes[i].Content}");
        }

        Console.WriteLine();
    }
}
catch (Exception ex)
{
    Console.Error.WriteLine($"\nError during research: {ex.Message}");
    Environment.ExitCode = 1;
}

// ═══════════════════════════════════════════════════════════════
//  Tool implementations
// ═══════════════════════════════════════════════════════════════

/// <summary>Stores research notes collected by the agent during investigation.</summary>
sealed class ResearchNotebook
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings during research.")]
    public string TakeNote(
        [Description("Brief title for the note")] string title,
        [Description("The finding or insight to record")] string content)
    {
        _notes.Add(new Note(title, content));
        Console.WriteLine($"  📝 Note saved: {title}");
        return $"Note saved: \"{title}\" ({_notes.Count} total notes).";
    }

    [Description("Retrieve all saved research notes for review and summarization.")]
    public IReadOnlyList<Note> GetAllNotes()
    {
        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
        return _notes.AsReadOnly();
    }
}

sealed record Note(string Title, string Content);

/// <summary>Provides web search and page fetching capabilities using DuckDuckGo.</summary>
sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information. Returns results with titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken: cancellationToken);
            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"\n");

            // Instant answer / abstract
            var abstractText = json.GetProperty("AbstractText").GetString();
            var abstractSource = json.GetProperty("AbstractSource").GetString();
            var abstractUrl = json.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                sb.AppendLine($"## Summary from {abstractSource}");
                sb.AppendLine(abstractText);
                if (!string.IsNullOrWhiteSpace(abstractUrl))
                    sb.AppendLine($"Source: {abstractUrl}");
                sb.AppendLine();
            }

            // Related topics
            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                var count = 0;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (count >= 8) break;

                    if (topic.TryGetProperty("Text", out var textEl))
                    {
                        var text = textEl.GetString();
                        if (string.IsNullOrWhiteSpace(text)) continue;

                        sb.AppendLine($"- {text}");
                        if (topic.TryGetProperty("FirstURL", out var urlEl))
                        {
                            var topicUrl = urlEl.GetString();
                            if (!string.IsNullOrWhiteSpace(topicUrl))
                                sb.AppendLine($"  URL: {topicUrl}");
                        }

                        count++;
                    }
                    else if (topic.TryGetProperty("Topics", out var subTopics))
                    {
                        // Nested topic group
                        foreach (var sub in subTopics.EnumerateArray())
                        {
                            if (count >= 8) break;
                            if (sub.TryGetProperty("Text", out var subText))
                            {
                                var st = subText.GetString();
                                if (!string.IsNullOrWhiteSpace(st))
                                {
                                    sb.AppendLine($"- {st}");
                                    if (sub.TryGetProperty("FirstURL", out var subUrl))
                                    {
                                        var su = subUrl.GetString();
                                        if (!string.IsNullOrWhiteSpace(su))
                                            sb.AppendLine($"  URL: {su}");
                                    }

                                    count++;
                                }
                            }
                        }
                    }
                }
            }

            var result = sb.ToString().Trim();
            return result.Length > 100
                ? result
                : $"Limited results for \"{query}\". Try rephrasing the query or searching for more specific terms.";
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetch and extract text content from a URL for deeper reading.")]
    public async Task<string> FetchPageAsync(
        [Description("The HTTP or HTTPS URL to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");

        try
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)
                || (uri.Scheme != "http" && uri.Scheme != "https"))
            {
                return "Invalid URL. Provide a valid HTTP or HTTPS URL.";
            }

            using var response = await httpClient.GetAsync(uri, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = StripHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated at 4000 characters]";

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch {url}: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
        // Remove HTML tags
        html = Regex.Replace(html, @"<[^>]+>", " ");
        // Decode common HTML entities
        html = html
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        html = Regex.Replace(html, @"\s+", " ").Trim();
