/// <summary>Provides web search and page fetching capabilities using DuckDuckGo.</summary>
sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information. Returns results with titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken: cancellationToken);
            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"\n");

            // Instant answer / abstract
            var abstractText = json.GetProperty("AbstractText").GetString();
            var abstractSource = json.GetProperty("AbstractSource").GetString();
            var abstractUrl = json.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                sb.AppendLine($"## Summary from {abstractSource}");
                sb.AppendLine(abstractText);
                if (!string.IsNullOrWhiteSpace(abstractUrl))
                    sb.AppendLine($"Source: {abstractUrl}");
                sb.AppendLine();
            }

            // Related topics
            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                var count = 0;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (count >= 8) break;

                    if (topic.TryGetProperty("Text", out var textEl))
                    {
                        var text = textEl.GetString();
                        if (string.IsNullOrWhiteSpace(text)) continue;

                        sb.AppendLine($"- {text}");
                        if (topic.TryGetProperty("FirstURL", out var urlEl))
                        {
                            var topicUrl = urlEl.GetString();
                            if (!string.IsNullOrWhiteSpace(topicUrl))
                                sb.AppendLine($"  URL: {topicUrl}");
                        }

                        count++;
                    }
                    else if (topic.TryGetProperty("Topics", out var subTopics))
                    {
                        // Nested topic group
                        foreach (var sub in subTopics.EnumerateArray())
                        {
                            if (count >= 8) break;
                            if (sub.TryGetProperty("Text", out var subText))
                            {
                                var st = subText.GetString();
                                if (!string.IsNullOrWhiteSpace(st))
                                {
                                    sb.AppendLine($"- {st}");
                                    if (sub.TryGetProperty("FirstURL", out var subUrl))
                                    {
                                        var su = subUrl.GetString();
                                        if (!string.IsNullOrWhiteSpace(su))
                                            sb.AppendLine($"  URL: {su}");
                                    }

                                    count++;
                                }
                            }
                        }
                    }
                }
            }

            var result = sb.ToString().Trim();
            return result.Length > 100
                ? result
                : $"Limited results for \"{query}\". Try rephrasing the query or searching for more specific terms.";
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetch and extract text content from a URL for deeper reading.")]
    public async Task<string> FetchPageAsync(
        [Description("The HTTP or HTTPS URL to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");

        try
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)
                || (uri.Scheme != "http" && uri.Scheme != "https"))
            {
                return "Invalid URL. Provide a valid HTTP or HTTPS URL.";
            }

            using var response = await httpClient.GetAsync(uri, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = StripHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated at 4000 characters]";

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch {url}: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
        // Remove HTML tags
        html = Regex.Replace(html, @"<[^>]+>", " ");
        // Decode common HTML entities
        html = html
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        html = Regex.Replace(html, @"\s+", " ").Trim();
        return html;
    }
}

