                                if (!string.IsNullOrWhiteSpace(st))
                                {
                                    sb.AppendLine($"- {st}");
                                    if (sub.TryGetProperty("FirstURL", out var subUrl))
                                    {
                                        var su = subUrl.GetString();
                                        if (!string.IsNullOrWhiteSpace(su))
                                            sb.AppendLine($"  URL: {su}");
                                    }

                                    count++;
                                }
                            }
                        }
                    }
                }
            }

            var result = sb.ToString().Trim();
            return result.Length > 100
                ? result
                : $"Limited results for \"{query}\". Try rephrasing the query or searching for more specific terms.";
        }
